CATEGORY_BRIDGES: Dict[str, Tuple[str, ...]] = {
    "equipment_constraints": ("location_environment",),
    "home_living_conditions": ("location_environment",),
    "location_environment": ("home_living_conditions", "equipment_constraints"),
}


def phrase_matches(lowered_text: str, tokens: set[str], phrase: str) -> bool:
    return phrase in lowered_text if " " in phrase else phrase in tokens


def cue_hits(text: str) -> Dict[str, List[str]]:
    lowered = text.lower()
    tokens = set(tokenized(lowered))
    hits: Dict[str, List[str]] = {}
    for category, phrase_weights in PARENT_STATE_CUES.items():
        matched = [phrase for phrase in phrase_weights if phrase_matches(lowered, tokens, phrase)]
        if matched:
            matched.sort(key=lambda phrase: (-phrase_weights[phrase], phrase))
            hits[category] = matched[:6]
    return hits


def cue_score(cues: Dict[str, List[str]]) -> int:
    score = 0
    for category, phrases in cues.items():
        weights = PARENT_STATE_CUES[category]
        score += sum(weights[phrase] for phrase in phrases)
    return score


def cue_categories(text: str) -> set[str]:
    return set(cue_hits(text))


def update_marker_hits(text: str) -> List[str]:
    lowered = text.lower()
    tokens = set(tokenized(lowered))
    return [marker for marker in UPDATE_MARKERS if phrase_matches(lowered, tokens, marker)][:5]


def short_session_summary(row: STALERow, index: int, max_chars: int = 700) -> str:
    body = session_text(row.haystack_sessions[index]).replace("\n", " ")
    return trim_text(body, max_chars)


def relevant_update_categories(query: str, premise_indices: Sequence[int], row: STALERow) -> set[str]:
    categories = cue_categories(query)
    lowered_query = query.lower()
    if any(phrase in lowered_query for phrase in ("still live", "place i live", "where i live", "climate", "city", "altitude")):
        categories.add("location_environment")
    if any(phrase in lowered_query for phrase in ("home", "room", "house", "window", "comfortable")):
        categories.add("home_living_conditions")
    if any(phrase in lowered_query for phrase in ("contractor", "employee", "dental", "tax", "benefit")):
        categories.add("employment_benefits")
    if any(phrase in lowered_query for phrase in ("catholic", "parish", "spiritual", "prayer", "relig")):
        categories.add("affiliation_practice")
    for index in premise_indices[:4]:
        categories.update(cue_categories(session_text(row.haystack_sessions[index])))
    bridged = set(categories)
    for category in categories:
        bridged.update(CATEGORY_BRIDGES.get(category, ()))
    return bridged


def score_update_candidate(
    index: int,
    row: STALERow,
    candidate_indices: set[int],
    target_categories: set[str],
) -> Tuple[float, Dict[str, List[str]], List[str]]:
    text = session_text(row.haystack_sessions[index])
    cues = cue_hits(text)
    markers = update_marker_hits(text)
    if not cues and not markers:
        return 0.0, cues, markers
    categories = set(cues)
    score = float(cue_score(cues))
    if categories & target_categories:
        score += 10.0
    if len(categories & target_categories) >= 2:
        score += 4.0
    if "location_environment" in categories and any(
        phrase in text.lower() for phrase in ("ocean", "tide", "sand", "scorpion", "dry heat", "red grit")
    ):
        score += 5.0
    if markers:
        score += min(4, len(markers))
    if index in candidate_indices:
        score += 1.0
    score += index / max(len(row.haystack_sessions), 1)
    return score, cues, markers


def build_conflict_scan(row: STALERow, adapter: TaskAdapter, candidate_indices: Sequence[int]) -> str:
    query = row.probing_queries[adapter.dim_key]
    premise_candidates = bm25_top_session_indices(row, query, min(8, len(row.haystack_sessions)))
    candidate_set = set(candidate_indices)
    target_categories = relevant_update_categories(query, premise_candidates, row)
    update_candidates: List[Tuple[float, int, Dict[str, List[str]], List[str]]] = []

    earliest_premise = min(premise_candidates) if premise_candidates else 0
    for index, session in enumerate(row.haystack_sessions):
        if index <= earliest_premise:
            continue
        score, cues, markers = score_update_candidate(index, row, candidate_set, target_categories)
        if score <= 0:
            continue
        update_candidates.append((score, index, cues, markers))

    update_candidates.sort(key=lambda item: (-item[0], item[1]))
    update_candidates = update_candidates[:18]
    bridge_pairs = []
    for old_index in premise_candidates[:5]:
        for _, new_index, cues, markers in update_candidates[:12]:
            if new_index <= old_index:
                continue
            bridge_pairs.append((old_index, new_index, cues, markers))
            if len(bridge_pairs) >= 14:
                break
        if len(bridge_pairs) >= 14:
            break

    lines = [
        "[Heuristic conflict scan; non-gold, derived only from the query and conversation history.]",
        "Use this as a checklist, not as ground truth. Verify every suggested chain against the sessions.",
        f"Probing query: {query}",
        f"Target parent-state categories: {', '.join(sorted(target_categories)) or 'none'}",
        "",
        "Potential premise/old-state sessions:",
    ]
    for index in premise_candidates[:8]:
        lines.append(
            f"- Session {index + 1} [Time: {row.timestamps[index]}]: {short_session_summary(row, index)}"
        )
    lines.append("")
    lines.append("Later parent-state update candidates:")
    for _, index, cues, markers in update_candidates:
        cue_text = "; ".join(f"{category}={','.join(items)}" for category, items in cues.items()) or "none"
        marker_text = ",".join(markers) or "none"
        lines.append(
            f"- Session {index + 1} [Time: {row.timestamps[index]}] markers={marker_text} cues={cue_text}: "
            f"{short_session_summary(row, index)}"
        )
    lines.append("")
    lines.append("Candidate indirect invalidation chains to check:")
    for old_index, new_index, cues, markers in bridge_pairs:
        cue_text = "; ".join(f"{category}={','.join(items)}" for category, items in cues.items()) or "none"
        marker_text = ",".join(markers) or "none"
        lines.append(
            f"- Session {old_index + 1} -> Session {new_index + 1}: later markers={marker_text}; later cues={cue_text}. "
            "Check whether the later parent-state change makes the older premise stale or unknown-current."
        )
    return "\n".join(lines)


def session_indices_for_variant(row: STALERow, adapter: TaskAdapter, variant: str, top_k: int, task_candidate_k: int) -> List[int]:
    if variant == "official_full_context":
        return list(range(len(row.haystack_sessions)))
    if variant == "oracle_relevant_sessions":
        return sorted(set(row.relevant_session_index))
    if variant == "bm25_sessions":
        return bm25_top_session_indices(row, row.probing_queries[adapter.dim_key], top_k)
    if variant == "scope_time_state_task_adapter":
        return bm25_top_session_indices(row, row.probing_queries[adapter.dim_key], task_candidate_k)
    raise ValueError(f"unsupported STALE variant={variant}")


def trim_text(text: str, max_chars: int) -> str:
    if len(text) <= max_chars:
        return text
    return text[: max_chars // 2] + "\n[...TRUNCATED...]\n" + text[-max_chars // 2 :]


def build_history_context(
    row: STALERow,
    session_indices: Sequence[int],
    max_context_chars: int,
    max_session_chars: int,
) -> str:
    chunks: List[str] = []
    total_chars = 0
    for rank, index in enumerate(session_indices, start=1):
        if index < 0 or index >= len(row.haystack_sessions):
            continue
        timestamp = row.timestamps[index] if index < len(row.timestamps) else ""
        body = trim_text(session_text(row.haystack_sessions[index]), max_session_chars)
        chunk = (
            f"=== Session {index + 1} [Time: {timestamp}] [retrieval_rank: {rank}] ===\n"
            f"{body}"
        )
        remaining = max_context_chars - total_chars
        if remaining <= 0:
            break
        if len(chunk) > remaining:
            if chunks and remaining < 1000:
                break
            chunk = chunk[:remaining] + "\n[CONTEXT_TRUNCATED]"
        chunks.append(chunk)
        total_chars += len(chunk)
    return "\n\n".join(chunks)


def official_system_prompt(adapter: TaskAdapter) -> str:
    if adapter.task_type == "implicit_policy_adaptation":
        task_action = "respond to the user's latest query directly"
        query_label = "latest query"
    else:
        task_action = "accurately answer the question"
        query_label = "question"
    return (
        "You are a helpful assistant. Review the following conversation history with the user, then "
        f"{task_action}. The benchmark task is STALE {adapter.task_name}. "
        f"Use only the conversation history when answering the {query_label}. "
        "Return strict JSON with key answer."
    )


def official_user_prompt(row: STALERow, adapter: TaskAdapter, context: str, variant: str) -> str:
    label = "Latest Query" if adapter.task_type == "implicit_policy_adaptation" else "Question"
    return (
        f"Benchmark: STALE\n"
        f"Variant: {variant}\n"
        f"Task: {adapter.task_name}\n"
        f"Task instruction: {adapter.task_instruction}\n\n"
        f"[Conversation History]\n{context}\n\n"
        f"[{label}]\n{row.probing_queries[adapter.dim_key]}\n\n"
        f"Respond as JSON only:\n{adapter.response_schema(variant)}"
    )


def evidence_system_prompt(adapter: TaskAdapter) -> str:
    return (
        "You are the evidence extraction stage of a Scope-Time-State memory pipeline for STALE. "
        "Use only the provided conversation sessions. Do not answer the probing query yet. "
        "Identify current-state evidence, stale or superseded claims, implicit invalidation links, "
        "and the minimal session indices needed for answer composition. "
        f"The active STALE task is {adapter.task_name}. Return strict JSON only."
    )


