def answer_system_prompt(adapter: TaskAdapter) -> str:
    return (
        "You are the answer composition stage of a Scope-Time-State memory pipeline for STALE. "
        "Use the extracted evidence JSON as your grounding. The evidence was selected from the user's "
        "conversation history. Apply state resolution before answering, and do not use stale claims as current. "
        f"The active STALE task is {adapter.task_name}. Return strict JSON only."
    )


def answer_user_prompt(row: STALERow, adapter: TaskAdapter, extraction: Dict[str, object]) -> str:
    evidence_json = json.dumps(extraction, ensure_ascii=False, indent=2)
    return (
        f"Benchmark: STALE\n"
        f"Task: {adapter.task_name}\n"
        f"Answer instruction: {adapter.answer_instruction}\n"
        f"Probing query: {row.probing_queries[adapter.dim_key]}\n\n"
        f"Extracted evidence JSON:\n{evidence_json}\n\n"
        f"Respond as JSON only:\n{adapter.response_schema('scope_time_state_task_adapter')}"
    )


def extract_answer(raw: Dict[str, object]) -> str:
    answer = raw.get("answer")
    if isinstance(answer, str):
        return answer.strip()
    if answer is None:
        return json.dumps(raw, ensure_ascii=False)
    return str(answer)


def run_task(
    client: LLMClient,
    row: STALERow,
    adapter: TaskAdapter,
    variant: str,
    top_k: int,
    task_candidate_k: int,
    max_context_chars: int,
    max_session_chars: int,
    task_max_session_chars: int,
) -> Dict[str, object]:
    start = time.perf_counter()
    session_indices = session_indices_for_variant(row, adapter, variant, top_k, task_candidate_k)
    if variant == "scope_time_state_task_adapter":
        context = build_history_context(row, session_indices, max_context_chars, task_max_session_chars)
        conflict_scan = build_conflict_scan(row, adapter, session_indices)
        extraction = client.complete_json(
            evidence_system_prompt(adapter),
            evidence_user_prompt(row, adapter, context, conflict_scan),
        )
        raw = client.complete_json(answer_system_prompt(adapter), answer_user_prompt(row, adapter, extraction))
        raw.setdefault("pipeline_trace", {})
        trace = raw["pipeline_trace"] if isinstance(raw["pipeline_trace"], dict) else {}
        trace.update(
            {
                "pipeline": variant,
                "candidate_session_indices": [index + 1 for index in session_indices],
                "conflict_scan": conflict_scan,
                "extraction": extraction,
            }
        )
        raw["pipeline_trace"] = trace
    else:
        context = build_history_context(row, session_indices, max_context_chars, max_session_chars)
        raw = client.complete_json(official_system_prompt(adapter), official_user_prompt(row, adapter, context, variant))
        raw.setdefault("pipeline_trace", {})
        trace = raw["pipeline_trace"] if isinstance(raw["pipeline_trace"], dict) else {}
        trace.update(
            {
                "pipeline": variant,
                "candidate_session_indices": [index + 1 for index in session_indices],
            }
        )
        raw["pipeline_trace"] = trace
    elapsed = time.perf_counter() - start
    return {
        "uid": row.uid,
        "conflict_type": row.conflict_type,
        "task_type": adapter.task_type,
        "dim_key": adapter.dim_key,
        "response_key": adapter.response_key,
        "meta_key": adapter.meta_key,
        "answer": extract_answer(raw),
        "elapsed_seconds": elapsed,
        "raw": raw,
    }


def empty_answer_record(row: STALERow, model: str, variant: str) -> Dict[str, object]:
    return {
        "uid": row.uid,
        "target_model": model,
        "target_model_responses": {
            "dim1_response": "",
            "dim2_response": "",
            "dim3_response": "",
        },
        "target_model_meta": {
            "dim1_meta": {},
            "dim2_meta": {},
            "dim3_meta": {},
        },
        "stale_meta": {
            "variant": variant,
            "conflict_type": row.conflict_type,
        },
    }


def build_official_answer_records(
    rows: Sequence[STALERow],
    task_results: Sequence[Dict[str, object]],
    model: str,
    variant: str,
) -> List[Dict[str, object]]:
    records = {row.uid: empty_answer_record(row, model, variant) for row in rows}
    for result in task_results:
        record = records[str(result["uid"])]
        response_key = str(result["response_key"])
        meta_key = str(result["meta_key"])
        record["target_model_responses"][response_key] = str(result["answer"])
        record["target_model_meta"][meta_key] = {
            "elapsed_seconds": result["elapsed_seconds"],
            "usage": {},
            "task_type": result["task_type"],
        }
    return list(records.values())


def official_judge_user_prompt(row: STALERow, answer_record: Dict[str, object]) -> str:
    responses = answer_record.get("target_model_responses", {})
    queries = row.probing_queries
    return f"""
[Ground Truth Context]
- M_old: "{row.m_old}"
- M_new: "{row.m_new}"
- Hidden Logic: {row.explanation}

--------------------------------------------------
[Dimension 1: Explicit Probing]
Question 1: {queries.get('dim1_query', '')}
Target Model Response 1: {responses.get('dim1_response', '')}

--------------------------------------------------
[Dimension 2: Adversarial Robustness]
Question 2: {queries.get('dim2_query', '')}
Target Model Response 2: {responses.get('dim2_response', '')}

--------------------------------------------------
[Dimension 3: Implicit Task]
Question 3: {queries.get('dim3_query', '')}
Target Model Response 3: {responses.get('dim3_response', '')}
""".strip()


def safe_mean(values: Iterable[float]) -> Optional[float]:
    usable = [float(value) for value in values]
    if not usable:
        return None
    return round(sum(usable) / len(usable), 4)


def run_judge(
    judge_client: LLMClient,
    rows: Sequence[STALERow],
    answer_records: Sequence[Dict[str, object]],
) -> Dict[str, object]:
    rows_by_uid = {row.uid: row for row in rows}
    details: List[Dict[str, object]] = []
    for record in answer_records:
        uid = str(record["uid"])
        row = rows_by_uid[uid]
        print(f"judging stale / {uid}", flush=True)
        started = time.perf_counter()
        evaluation = judge_client.complete_json(OFFICIAL_JUDGE_SYSTEM_PROMPT, official_judge_user_prompt(row, record))
        details.append(
            {
                "uid": uid,
                "conflict_type": row.conflict_type,
                "evaluation": evaluation,
                "judge_meta": {"elapsed_seconds": time.perf_counter() - started},
            }
        )

    summary: Dict[str, object] = {}
    for conflict_type in sorted({row.conflict_type for row in rows}):
        type_details = [detail for detail in details if detail["conflict_type"] == conflict_type]
        dim_scores: Dict[str, Optional[float]] = {}
        for dim in ("dim1", "dim2", "dim3"):
            values = [
                1.0 if detail["evaluation"].get(f"{dim}_eval", {}).get("pass") else 0.0
                for detail in type_details
            ]
            dim_scores[f"{dim}_accuracy"] = safe_mean(values)
        all_values = [
            1.0 if detail["evaluation"].get(f"{dim}_eval", {}).get("pass") else 0.0
            for detail in type_details
            for dim in ("dim1", "dim2", "dim3")
        ]
        dim_scores["overall_accuracy"] = safe_mean(all_values)
        dim_scores["n_cases"] = len(type_details)
        summary[conflict_type] = dim_scores
    return {"summary": summary, "details": details}


def summarize_task_results(rows: Sequence[STALERow], tasks: Sequence[Tuple[STALERow, TaskAdapter]]) -> Dict[str, object]:
    return {
        "n_scenarios": len(rows),
        "n_tasks": len(tasks),
        "conflict_counts": dict(Counter(row.conflict_type for row in rows)),
        "task_counts": dict(Counter(adapter.task_type for _, adapter in tasks)),
    }


def print_summary(results: Sequence[Dict[str, object]]) -> None:
    print("STALE official benchmark adapter")
    print("Tasks: dim1=state_resolution dim2=premise_resistance dim3=implicit_policy_adaptation")
    print()
    print(f"{'variant':<34} {'scenarios':>9} {'tasks':>7} {'T1':>5} {'T2':>5}")
    print("-" * 66)
    for result in results:
        summary = result["summary"]
        conflict_counts = summary.get("conflict_counts", {})
        print(
            f"{result['variant']:<34} {summary['n_scenarios']:>9} {summary['n_tasks']:>7} "
            f"{conflict_counts.get('T1', 0):>5} {conflict_counts.get('T2', 0):>5}"
        )
    print()


def main() -> int:
    args = parse_args()
    load_dotenv()
    data_path = Path(args.data)
    output_path = Path(args.output)
    cache_path = Path(args.cache)

    if args.list_tasks:
        print("Supported STALE task adapters:")
        for task_type in OFFICIAL_TASK_TYPES:
            adapter = get_adapter(task_type)
            print(f"- {task_type}: {adapter.task_name} ({adapter.dim_key} -> {adapter.response_key})")
        print("Supported variants:")
        for variant in SUPPORTED_VARIANTS:
            print(f"- {variant}")
        return 0

    for variant in args.variants:
        if variant not in SUPPORTED_VARIANTS:
            known = ", ".join(SUPPORTED_VARIANTS)
            print(f"unsupported STALE variant: {variant}; supported variants: {known}", file=sys.stderr)
            return 2

    try:
        task_types = selected_task_types(args.task_types)
    except ValueError as exc:
        print(str(exc), file=sys.stderr)
        return 2

    if args.judge and set(task_types) != set(OFFICIAL_TASK_TYPES):
        print("--judge requires all three STALE task types so the official all-in-one rubric is meaningful.", file=sys.stderr)
        return 2

    rows = select_rows(load_rows(data_path), args.conflict_types, args.limit_cases, args.limit_per_conflict)
    tasks = iter_tasks(rows, task_types, args.limit_per_task)

    if args.dry_run:
        summary = summarize_task_results(rows, tasks)
        print(
            f"valid STALE benchmark: records={len(rows)} tasks={len(tasks)} "
            f"conflicts={summary['conflict_counts']} task_counts={summary['task_counts']}"
        )
        print(f"data_path={data_path}")
        print(f"variants={','.join(args.variants)}")
        return 0

    try:
        api_key, model, api_base = provider_config(args.provider)
    except RuntimeError as exc:
        print(f"Config error: {exc}", file=sys.stderr)
        return 2

    client = LLMClient(
        provider=args.provider,
        model=model,
        api_key=api_key,
        api_base=api_base,
        cache_path=cache_path,
        use_cache=not args.no_cache,
    )

    judge_client: Optional[LLMClient] = None
    judge_model: Optional[str] = None
    if args.judge:
        try:
            judge_api_key, judge_model, judge_api_base = provider_config(args.judge_provider)
        except RuntimeError as exc:
            print(f"Judge config error: {exc}", file=sys.stderr)
            return 2
        judge_cache = cache_path.with_name(f"{cache_path.stem}.{args.judge_provider}_judge.json")
        judge_client = LLMClient(
            provider=args.judge_provider,
            model=judge_model,
            api_key=judge_api_key,
            api_base=judge_api_base,
            cache_path=judge_cache,
            use_cache=not args.no_cache,
        )

    print(f"target_provider={args.provider} target_model={model}", flush=True)
    if judge_client is not None:
        print(f"judge_provider={args.judge_provider} judge_model={judge_model}", flush=True)

    results: List[Dict[str, object]] = []
    try:
        for variant in args.variants:
            variant_task_results: List[Dict[str, object]] = []
            for row, adapter in tasks:
                print(f"running {variant} / {row.uid} / {adapter.task_type}", flush=True)
                variant_task_results.append(
                    run_task(
                        client,
                        row,
                        adapter,
                        variant,
                        args.top_k,
                        args.task_candidate_k,
                        args.max_context_chars,
                        args.max_session_chars,
                        args.task_max_session_chars,
                    )
                )
                time.sleep(0.2)
            answer_records = build_official_answer_records(rows, variant_task_results, model, variant)
            result: Dict[str, object] = {
                "benchmark": "STALE",
                "variant": variant,
                "data_path": str(data_path),
                "model_provider": args.provider,
                "model": model,
                "task_types": list(task_types),
                "summary": summarize_task_results(rows, tasks),
                "data": answer_records,
                "task_results": variant_task_results,
            }
            if judge_client is not None:
                result["judge_provider"] = args.judge_provider
                result["judge_model"] = judge_model
                result["judge"] = run_judge(judge_client, rows, answer_records)
            results.append(result)
    except LLMRequestError as exc:
        print("\nLLM request failed.", file=sys.stderr)
        print(f"provider: {exc.provider}", file=sys.stderr)
        print(f"model: {exc.model}", file=sys.stderr)
        print(f"endpoint: {exc.endpoint}", file=sys.stderr)
        print(f"error: {exc}", file=sys.stderr)
        return 1

    output_obj: Dict[str, object] = {
        "benchmark": "STALE",
        "official_dataset": "STALEproj/STALE",
        "results": results,
    }
    if len(results) == 1:
        output_obj["data"] = results[0]["data"]
        output_obj["summary"] = results[0]["summary"]
        if "judge" in results[0]:
            output_obj["judge"] = results[0]["judge"]

    print_summary(results)
    output_path.parent.mkdir(exist_ok=True)
    output_path.write_text(json.dumps(output_obj, ensure_ascii=False, indent=2) + "\n")
    print(f"Wrote {output_path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
